    LI_RELOAD_Y     = 0x02,         /* Reload index register Y */
    LI_REMOVE       = 0x04,         /* Load may be removed */
    LI_DONT_REMOVE  = 0x08,         /* Load may not be removed */
    LI_CHECK_ARG    = 0x10,         /* Load src might be modified later */
