#include <stdio.h>
#include <stdlib.h>

unsigned char a, b = 0;
unsigned char c = 10;
unsigned char d = 1;

int main(void) {
    if (b != 0) {
        b = 0;
    }

    a = c - (d >= 0);

    return !(a == 9);
}

